<?php
if (!defined('ABSPATH')) { exit; }
final class Elev8_OS_Business_Memory_Module {
 const SLUG='elev8-business-memory';
 public static function init():void{Elev8_OS_Business_Memory_Service::init();add_action('admin_menu',[__CLASS__,'menu'],26);add_action('admin_enqueue_scripts',[__CLASS__,'assets']);add_action('admin_post_elev8_os_save_memory',[__CLASS__,'save']);add_action('admin_post_elev8_os_memory_status',[__CLASS__,'status']);}
 public static function menu():void{add_submenu_page('elev8-os','Business Memory','Business Memory','manage_options',self::SLUG,[__CLASS__,'render']);}
 public static function assets(string $hook):void{if($hook==='elev8-os_page_'.self::SLUG)wp_enqueue_style('elev8-business-memory',ELEV8_OS_URL.'assets/css/business-memory.css',[],ELEV8_OS_VERSION);}
 private static function url(array $a=[]):string{return add_query_arg(array_merge(['page'=>self::SLUG],$a),admin_url('admin.php'));}
 public static function render():void{if(!current_user_can('manage_options'))wp_die('Permission denied.');$view=sanitize_key((string)($_GET['view']??'feed'));echo '<div class="wrap elev8-memory">';if(class_exists('Elev8_OS_CEO_Dashboard_Module'))Elev8_OS_CEO_Dashboard_Module::render_workspace_navigation('operations');echo '<header class="elev8-memory__hero"><div><p>DAILY OPERATIONS INTELLIGENCE</p><h1>Business Memory</h1><span>The official, searchable record of important conversations, decisions, and events.</span></div><a class="button button-primary button-hero" href="'.esc_url(self::url(['view'=>'new'])).'">Document conversation or event</a></header><nav class="elev8-memory__nav"><a href="'.esc_url(self::url()).'">Memory Feed</a><a href="'.esc_url(self::url(['view'=>'followups'])).'">Open Follow-Ups</a><a href="'.esc_url(self::url(['view'=>'intelligence'])).'">Patterns & Intelligence</a></nav>';
 if(isset($_GET['saved']))echo '<div class="notice notice-success"><p>Business Memory record saved.</p></div>';
 if($view==='new')self::form();elseif($view==='record')self::record(absint($_GET['id']??0));elseif($view==='followups')self::followups();elseif($view==='intelligence')self::intelligence();else self::feed();echo '</div>';}
 private static function form():void{?>
 <section class="elev8-memory__panel"><h2>Document a conversation or event</h2><p>Record confirmed facts objectively. Separate facts from opinions or assumptions.</p><form method="post" enctype="multipart/form-data" action="<?php echo esc_url(admin_url('admin-post.php'));?>" class="elev8-memory__form"><?php wp_nonce_field('elev8_memory_save');?><input type="hidden" name="action" value="elev8_os_save_memory"><div class="grid-3"><label>Date *<input type="date" name="event_date" value="<?php echo esc_attr(current_time('Y-m-d'));?>" required></label><label>Time<input type="time" name="event_time" value="<?php echo esc_attr(current_time('H:i'));?>"></label><label>Priority<select name="priority"><option value="low">Low</option><option value="normal" selected>Normal</option><option value="high">High</option><option value="critical">Critical</option></select></label></div><div class="grid-2"><label>Record type<select name="record_type"><option value="employee">Employee conversation</option><option value="customer">Customer interaction</option><option value="vendor">Vendor discussion</option><option value="operations">Operational issue</option><option value="maintenance">Maintenance event</option><option value="hr">HR matter</option><option value="safety">Safety incident</option><option value="decision">Business decision</option><option value="complaint">Complaint</option><option value="meeting">Meeting</option><option value="general">General observation</option></select></label><label>Location (optional)<input type="text" name="location"></label></div><label>Participants<input type="text" name="participants" placeholder="Names or roles, separated by commas"></label><label>Topic *<input type="text" name="topic" required></label><label>Objective summary *<textarea name="summary" rows="6" required placeholder="What happened or was discussed? Record confirmed facts and direct outcomes."></textarea></label><label>Decisions made<textarea name="decisions" rows="3"></textarea></label><fieldset><legend>Action items and owners</legend><?php for($i=0;$i<4;$i++):?><div class="action-row"><input type="text" name="action_items[<?php echo $i;?>][task]" placeholder="Action item"><input type="text" name="action_items[<?php echo $i;?>][owner]" placeholder="Owner"><input type="date" name="action_items[<?php echo $i;?>][due]"></div><?php endfor;?></fieldset><div class="grid-2"><label>Follow-up date<input type="date" name="follow_up_date"></label><label>Tags<input type="text" name="tags" placeholder="employee, HR, HEMP, maintenance"></label></div><label>Supporting attachments <small>Photos, PDFs, email exports, or documents—up to 8 files</small><input type="file" name="attachments[]" multiple accept="image/*,.pdf,.doc,.docx,.txt,.eml"></label><button class="button button-primary button-hero">Save to Business Memory</button></form></section><?php }
 public static function save():void{if(!current_user_can('manage_options'))wp_die('Permission denied.');check_admin_referer('elev8_memory_save');$id=Elev8_OS_Business_Memory_Service::save(wp_unslash($_POST),$_FILES,get_current_user_id());if(is_wp_error($id))wp_die(esc_html($id->get_error_message()));wp_safe_redirect(self::url(['saved'=>1]));exit;}
 private static function feed():void{$f=['s'=>sanitize_text_field((string)($_GET['s']??'')),'priority'=>sanitize_key((string)($_GET['priority']??'')),'status'=>sanitize_key((string)($_GET['status']??'')),'participant'=>sanitize_text_field((string)($_GET['participant']??''))];$items=Elev8_OS_Business_Memory_Service::query($f);echo '<form class="elev8-memory__filters"><input type="hidden" name="page" value="'.esc_attr(self::SLUG).'"><input name="s" value="'.esc_attr($f['s']).'" placeholder="Search topic or summary"><input name="participant" value="'.esc_attr($f['participant']).'" placeholder="Participant"><select name="priority"><option value="">All priorities</option>';foreach(['low','normal','high','critical'] as $x)echo '<option '.selected($f['priority'],$x,false).' value="'.$x.'">'.ucfirst($x).'</option>';echo '</select><select name="status"><option value="">All statuses</option>';foreach(['open','monitoring','resolved','archived'] as $x)echo '<option '.selected($f['status'],$x,false).' value="'.$x.'">'.ucfirst($x).'</option>';echo '</select><button class="button">Search</button></form><div class="elev8-memory__feed">';if(!$items)echo '<div class="elev8-memory__empty">No records found.</div>';foreach($items as $r){$d=$r['data'];echo '<a class="memory-card priority-'.esc_attr($d['priority']??'normal').'" href="'.esc_url(self::url(['view'=>'record','id'=>$r['post']->ID])).'"><div><span class="pill">'.esc_html(ucfirst($d['record_type']??'general')).'</span><span class="pill status">'.esc_html(ucfirst($r['status'])).'</span></div><h2>'.esc_html($d['topic']??$r['post']->post_title).'</h2><p>'.esc_html(wp_trim_words($d['summary']??'',32)).'</p><footer><span>'.esc_html(($d['date']??'').' '.($d['time']??'')).'</span><span>'.esc_html($d['participants']??'').'</span></footer></a>';}echo '</div>';}
 private static function record(int $id):void{$r=Elev8_OS_Business_Memory_Service::get($id);if(!$r){echo '<p>Record not found.</p>';return;}$d=$r['data'];echo '<section class="elev8-memory__panel record"><a href="'.esc_url(self::url()).'">← Back to memory</a><div class="record-head"><div><p>'.esc_html(strtoupper($d['record_type']??'general')).'</p><h1>'.esc_html($d['topic']??'').'</h1></div><strong class="priority-badge priority-'.esc_attr($d['priority']??'normal').'">'.esc_html(ucfirst($d['priority']??'normal')).'</strong></div><dl><dt>Date and time</dt><dd>'.esc_html(($d['date']??'').' '.($d['time']??'')).'</dd><dt>Participants</dt><dd>'.esc_html($d['participants']??'Unavailable').'</dd><dt>Location</dt><dd>'.esc_html($d['location']?:'Not specified').'</dd></dl><h2>Objective summary</h2><div class="prose">'.nl2br(esc_html($d['summary']??'')).'</div><h2>Decisions made</h2><div class="prose">'.nl2br(esc_html($d['decisions']?:'None documented.')).'</div><h2>Action items</h2><ul class="actions">';foreach((array)($d['actions']??[]) as $a)echo '<li><strong>'.esc_html($a['task']).'</strong><span>Owner: '.esc_html($a['owner']?:'Unassigned').' · Due: '.esc_html($a['due']?:'No date').'</span></li>';if(empty($d['actions']))echo '<li>No action items documented.</li>';echo '</ul><h2>Attachments</h2><div class="attachments">';foreach((array)($d['attachments']??[]) as $aid){$url=wp_get_attachment_url($aid);if($url)echo '<a target="_blank" rel="noopener" href="'.esc_url($url).'">'.esc_html(get_the_title($aid)?:'Attachment').'</a>';}if(empty($d['attachments']))echo 'None';echo '</div><form method="post" action="'.esc_url(admin_url('admin-post.php')).'">';wp_nonce_field('elev8_memory_status_'.$id);echo '<input type="hidden" name="action" value="elev8_os_memory_status"><input type="hidden" name="id" value="'.$id.'"><select name="status">';foreach(['open','monitoring','resolved','archived'] as $x)echo '<option '.selected($r['status'],$x,false).' value="'.$x.'">'.ucfirst($x).'</option>';echo '</select> <button class="button">Update status</button></form></section>';}
 public static function status():void{$id=absint($_POST['id']??0);if(!current_user_can('manage_options'))wp_die('Permission denied.');check_admin_referer('elev8_memory_status_'.$id);Elev8_OS_Business_Memory_Service::set_status($id,sanitize_key((string)($_POST['status']??'')));wp_safe_redirect(self::url(['view'=>'record','id'=>$id]));exit;}
 private static function followups():void{$i=Elev8_OS_Business_Memory_Service::intelligence();echo '<section class="elev8-memory__panel"><h2>Open Follow-Ups</h2><p>'.count($i['open_actions']).' unresolved action items; '.count($i['overdue']).' overdue.</p><div class="followups">';foreach($i['open_actions'] as $a)echo '<a href="'.esc_url(self::url(['view'=>'record','id'=>$a['record']])).'"><strong>'.esc_html($a['task']).'</strong><span>'.esc_html($a['owner']?:'Unassigned').' · '.esc_html($a['due']?:'No due date').'</span></a>';if(!$i['open_actions'])echo '<p>No unresolved action items.</p>';echo '</div></section>';}
 private static function intelligence():void{$i=Elev8_OS_Business_Memory_Service::intelligence();echo '<div class="intel-grid"><article><strong>'.$i['records'].'</strong><span>Memory records</span></article><article><strong>'.count($i['open_actions']).'</strong><span>Open actions</span></article><article><strong>'.count($i['overdue']).'</strong><span>Overdue actions</span></article><article><strong>'.count($i['risks']).'</strong><span>High-priority risks</span></article></div><div class="grid-2-panels"><section class="elev8-memory__panel"><h2>Recurring signals</h2>';if($i['recurring'])foreach($i['recurring'] as $term=>$n)echo '<p><strong>'.esc_html(ucwords($term)).'</strong> — '.$n.' records</p>';else echo '<p>More records are needed to identify recurring patterns.</p>';echo '</section><section class="elev8-memory__panel"><h2>Recommended next steps</h2><ul>';if($i['overdue'])echo '<li>Review and assign the '.count($i['overdue']).' overdue action items.</li>';if($i['risks'])echo '<li>Review unresolved high-priority records before the next operations meeting.</li>';if($i['recurring'])echo '<li>Create a corrective plan for the most repeated issue: '.esc_html(ucwords(array_key_first($i['recurring']))).'.</li>';if(!$i['overdue']&&!$i['risks']&&!$i['recurring'])echo '<li>Continue documenting important events to strengthen Business Memory intelligence.</li>';echo '</ul><p class="muted">These are rule-based recommendations. Original records are never rewritten.</p></section></div>';}
}
